public static Option create(String opt) throws IllegalArgumentException
{
    // Ensure the OptionBuilder is properly reset before creating a new Option
    OptionBuilder.reset();

    // create the option
    Option option = new Option(opt, OptionBuilder.description);

    // set the option properties
    option.setLongOpt(OptionBuilder.longopt);
    option.setRequired(OptionBuilder.required);
    option.setOptionalArg(OptionBuilder.optionalArg);
    option.setArgs(OptionBuilder.numberOfArgs);
    option.setType(OptionBuilder.type);
    option.setValueSeparator(OptionBuilder.valuesep);
    option.setArgName(OptionBuilder.argName);

    // reset the OptionBuilder properties after creating the Option
    OptionBuilder.reset();

    // return the Option instance
    return option;
}

public static Option create(String opt) throws IllegalArgumentException
{
    // Reset the OptionBuilder properties at the beginning
    description = null;
    longopt = null;
    required = false;
    optionalArg = false;
    numberOfArgs = Option.UNINITIALIZED;
    type = null;
    valuesep = '\0';
    argName = null;

    // create the option with initial description
    Option option = new Option(opt, description);

    // set the option properties
    option.setLongOpt(longopt);
    option.setRequired(required);
    option.setOptionalArg(optionalArg);
    option.setArgs(numberOfArgs);
    option.setType(type);
    option.setValueSeparator(valuesep);
    option.setArgName(argName);

    // reset the OptionBuilder properties again to ensure no carryover
    OptionBuilder.reset();

    // return the Option instance
    return option;
}

